/* global document, Office, fetch */

const FLASK_URL = "https://localhost:5000/check";

Office.onReady((info) => {
  if (info.host === Office.HostType.Outlook) {
    runCheck();
    document.getElementById("recheck-button").onclick = runCheck;
  }
});

async function runCheck() {
  showLoading();

  try {
    const rawBody = await getDraftBody();
    const { draft, history } = splitDraftAndHistory(rawBody);

    const response = await fetch(FLASK_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        email: draft,
        client_email: history
      })
    });

    if (!response.ok) {
      throw new Error(`Server returned ${response.status}`);
    }

    const result = await response.json();
    renderResult(result);
  } catch (err) {
    showError(`Couldn't reach the Compass service. Make sure Flask is running at ${FLASK_URL}. Details: ${err.message}`);
  }
}

function splitDraftAndHistory(rawBody) {
  // Splits a reply body into the user's typed portion and the quoted history.
  // Outlook on web, desktop, and mobile all use slightly different markers, so we
  // try several patterns and cut at whichever appears earliest in the text.
  if (!rawBody) return { draft: "", history: "" };

  const markers = [
    /\n\s*From:\s.+\nSent:/i,                  // Outlook desktop classic
    /\n\s*On .+ wrote:/i,                       // Outlook web / Gmail style
    /\n\s*On .+,.+ at .+ wrote:/i,              // Outlook web alternate
    /\n\s*-----Original Message-----/i,         // Older Outlook
    /\n\s*________________________________/,    // Outlook horizontal rule
    /\n\s*Sent from my iPhone/i,                // Mobile signature boundary
    /\nFrom: .+@.+\..+/i                        // Loose fallback: From: line with email
  ];

  let earliest = rawBody.length;
  for (const marker of markers) {
    const match = rawBody.match(marker);
    if (match && match.index < earliest) {
      earliest = match.index;
    }
  }

  return {
    draft: rawBody.substring(0, earliest).trim(),
    history: rawBody.substring(earliest).trim()
  };
}

function getDraftBody() {
  return new Promise((resolve, reject) => {
    Office.context.mailbox.item.body.getAsync(
      Office.CoercionType.Text,
      (asyncResult) => {
        if (asyncResult.status === Office.AsyncResultStatus.Succeeded) {
          resolve(asyncResult.value || "");
        } else {
          reject(new Error("Couldn't read the draft body."));
        }
      }
    );
  });
}

function showLoading() {
  document.getElementById("status-section").style.display = "block";
  document.getElementById("results-section").style.display = "none";
  document.getElementById("error-section").style.display = "none";
  document.getElementById("recheck-button").style.display = "none";
}

function showError(message) {
  document.getElementById("status-section").style.display = "none";
  document.getElementById("results-section").style.display = "none";
  document.getElementById("error-section").style.display = "block";
  document.getElementById("error-text").textContent = message;
  document.getElementById("recheck-button").style.display = "block";
}

function renderResult(result) {
  document.getElementById("status-section").style.display = "none";
  document.getElementById("error-section").style.display = "none";
  document.getElementById("results-section").style.display = "block";
  document.getElementById("recheck-button").style.display = "block";

  const statusEl = document.getElementById("overall-status");
  const status = (result.overall_status || "GREEN").toUpperCase();
  statusEl.className = "overall-status " + status.toLowerCase();

  const statusLabels = {
    RED: "🛑 Do not send — needs your attention",
    AMBER: "⚠️ Review before sending",
    GREEN: "✅ Looks good"
  };
  statusEl.textContent = statusLabels[status] || status;

  renderFlagGroup("red-flags-block", "red-flags-list", result.red_flags || []);
  renderFlagGroup("amber-flags-block", "amber-flags-list", result.amber_flags || []);
  renderFlagGroup("positive-notes-block", "positive-notes-list", result.positive_notes || []);
}

function renderFlagGroup(blockId, listId, items) {
  const block = document.getElementById(blockId);
  const list = document.getElementById(listId);
  list.innerHTML = "";

  if (!items || items.length === 0) {
    block.style.display = "none";
    return;
  }

  block.style.display = "block";

  items.forEach((item) => {
    const li = document.createElement("li");
    const primaryText = item.issue || item.note || "(no text)";
    const secondaryText = item.action || "";

    const issueDiv = document.createElement("div");
    issueDiv.className = "flag-issue";
    issueDiv.textContent = primaryText;
    li.appendChild(issueDiv);

    if (secondaryText) {
      const actionDiv = document.createElement("div");
      actionDiv.className = "flag-action";
      actionDiv.textContent = secondaryText;
      li.appendChild(actionDiv);
    }

    list.appendChild(li);
  });
}